bool test_node_closure(const std::string& nodeName) {
    // 1. Create observer nodes
    auto sourceNode = std::make_shared<TestObserverClosure>("source");
    auto observerNode = std::make_shared<TestObserverClosure>(nodeName);

    // 2. Get observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Add observer relationship between nodes
    observerGraph.addObserver(sourceNode, observerNode);

    // 4. Notify target and verify observer was notified
    bool firstNotificationSuccess = false;
    {
        // Reset observer state before first test
        observerNode->reset();

        // Notify source node (which should propagate to observer)
        sourceNode->valueChanged(true);

        // Verify observer was notified
        if (observerNode->wasChanged()) {
            firstNotificationSuccess = true;
        }
    }

    // 5. Reset observer state
    observerNode->reset();

    // 6. Close observer node
    observerNode->close();

    // 7. Notify target again and verify observer was not notified after closure
    bool secondNotificationSuccess = false;
    {
        // Notify source node again
        sourceNode->valueChanged(true);

        // Verify observer was NOT notified after closure
