std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    using namespace reaction;

    // 1. Create a reactive variable for the sensor using reaction::var with initial value
    auto sensor = var(initialValue);

    // 2. Create two reactive variables to track recompute count and last processed value using reaction::var
    auto recomputeCount = var(0);
    auto lastProcessedValue = var(0.0);

    // 3. Create a calculation that uses the sensor value and updates the count/last value
    auto statusCalculation = calc([&]() -> std::string {
        double currentValue = sensor.get();
        double lastValue = lastProcessedValue.get();

        // Update recompute count when triggered
        recomputeCount.value(recomputeCount.get() + 1);

        // Update last processed value
        lastProcessedValue.value(currentValue);

        // Determine status based on levelThreshold
        if (currentValue > levelThreshold) {
            return "HIGH";
        } else {
            return "NORMAL";
        }
    });

    // 4. Apply a filter to the calculation using filter() method with a lambda that checks the difference between current and last value
    statusCalculation.filter([&](double currentValue, double lastValue) {
        return std::abs(currentValue - lastValue) >= diffThreshold;
    }, sensor, lastProcessedValue);

    // 5. Update the sensor with the first value using value() method
    sensor.value(firstUpdate);

    // 6. Get the recompute count after first update using get() method
    int firstCount = recomputeCount.get();

    // 7. Update the sensor with the second value using value() method
    sensor.value(secondUpdate);

    // 8. Get the recompute count after second update using get() method
    int secondCount = recomputeCount.get();

    // 9. Get the final status string using get() method on the calculation
    std::string finalStatus = statusCalculation.get();

    // 10. Return a tuple with the final status, first count, and second count
    return std::make_tuple(finalStatus, firstCount, secondCount);
}

}  // namespace test_reaction
