namespace test_reaction {

struct BatchExecuteResult {
    int recomputeCountBeforeBatch;
    int recomputeCountAfterBatch;
    int finalValue;
};

BatchExecuteResult test_batch_execute_update(int baseValue, int deltaA, int deltaB) {
    using namespace reaction;

    // 1. Create reactive variable varA with initial value baseValue
    auto varA = var(baseValue);

    // 2. Create reactive variable varB with initial value 0
    auto varB = var(0);

    // 3. Create reactive variable recomputeCounter with initial value 0
    auto recomputeCounter = var(0);

    // 4. Create calculation that depends on both variables
    auto calcAB = calc([&]() {
        // 5. In calculation, increment recompute counter
        recomputeCounter.value(recomputeCounter.get() + 1);

        // Return sum of varA and varB
        return varA.get() + varB.get();
    });

    // 6. Before batch, get current recompute counter value
    int recomputeCountBeforeBatch = recomputeCounter.get();

    // 7. Use batchExecute to update both variables
    batchExecute([&]() {
        varA.value(baseValue + deltaA);  // Update varA with baseValue + deltaA
        varB.value(deltaB);              // Update varB with deltaB
    });

    // 8. After batch, get updated recompute counter value
    int recomputeCountAfterBatch = recomputeCounter.get();

    // 9. Get final calculation value
    int finalValue = calcAB.get();

    // 10. Return BatchExecuteResult with all three values
    return BatchExecuteResult{
        recomputeCountBeforeBatch,
        recomputeCountAfterBatch,
        finalValue
    };
}

}  // namespace test_reaction
