        // Lock acquired within this scope with thread safety enabled
    } // Guard exits scope, mutex is automatically released

    // 8. Check lock status with safety enabled
    bool lockStatusWithSafety = conditionalMutex.isLocked();

    // 9. Return the results
    return {lockStatusWithoutSafety, lockStatusWithSafety};
}

}  // namespace test_reaction
