    // 11. Attempt to acquire shared lock with safety
    bool trySharedWithSafety = mutex.try_shared_lock();

    // 12. Unlock shared lock if acquired
    if (trySharedWithSafety) {
        mutex.unlock_shared();
    }

    // 13. Create ConditionalSharedLockGuard in a scope block again
    {
        reaction::ConditionalSharedLockGuard<reaction::ConditionalSharedMutex> guard(mutex);

        // 14. Attempt to acquire unique lock while shared lock is held with safety
        bool tryUniqueWhileSharedWithSafety = mutex.try_lock();

        // 15. Unlock unique lock if acquired
        if (tryUniqueWhileSharedWithSafety) {
            mutex.unlock();
        }
    } // 16. Exit guard scope

    // 17. Return SharedMutexResult with all four test results
    return SharedMutexResult{
        .trySharedWithoutSafety = trySharedWithoutSafety,
        .tryUniqueWhileSharedWithoutSafety = tryUniqueWhileSharedWithoutSafety,
        .trySharedWithSafety = trySharedWithSafety,
        .tryUniqueWhileSharedWithSafety = tryUniqueWhileSharedWithSafety
    };
}

}  // namespace test_reaction

