    // Call add() method on the pointer
    firstPtr->add(delta);

    // Get current value after first add
    int valueAfterFirstAdd = reactiveVar.get();

    // Get second pointer using getPtr() again
    auto secondPtr = reactiveVar.getPtr();

    // Call add() method on the second pointer
