  const int b = 5;
  const int c = 3;

  const auto snapshot = test_raw_expression_builders(a, b, c);

  // Initial expectations:
  // sum      = a + b
  // negated  = -(a + b)
  // chained  = -(a + b) * c
  EXPECT_EQ(snapshot.initialSum, a + b);
  EXPECT_EQ(snapshot.initialNegatedSum, -(a + b));
  EXPECT_EQ(snapshot.initialChainedValue, -(a + b) * c);

